module RefModule(
    input clk,
    input rst,
    output [4:0] count
);

    reg [4:0] unused_counter_reg;

    always @(posedge clk) begin
        if (!rst) begin
            unused_counter_reg <= 5'b11111;
        end else begin
            unused_counter_reg <= unused_counter_reg - 1;
        end
    end

    assign count = unused_counter_reg;

endmodule
